import PropTypes from 'prop-types'
import React from 'react'
import type { ISudokuContext } from './context'
import { SudokuContextType } from './context'
import { reducer } from './reducer'
import type { ISudokuState } from './state'
import { initSudokuState } from './state'

export interface ISudokuContextProviderProps {
  /**
   * Initial context data.
   */
  initialState?: Partial<ISudokuState>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

export const SudokuContextProvider: React.FC<ISudokuContextProviderProps> = props => {
  const { children, initialState } = props
  const [state, dispatch] = React.useReducer(reducer, initialState, initSudokuState)

  const context: ISudokuContext = React.useMemo(() => ({ state, dispatch }), [state, dispatch])
  return <SudokuContextType.Provider value={context}>{children}</SudokuContextType.Provider>
}

SudokuContextProvider.propTypes = {
  initialState: PropTypes.any,
  children: PropTypes.node.isRequired,
}

SudokuContextProvider.displayName = 'SudokuContextProvider'
