import { GameRunningStatus } from '@kyokuya/react-game-core'
import { SudokuActionType, SudokuContextType } from '@kyokuya/react-game-sudoku-core'
import GamePausedIcon from '@mui/icons-material/PauseCircleFilled'
import GamePendingIcon from '@mui/icons-material/PlayArrow'
import Button from '@mui/material/Button'
import React from 'react'

export const GameOverlay: React.FC = () => {
  const { state, dispatch } = React.useContext(SudokuContextType)

  return React.useMemo(() => {
    // Start game.
    const startGame = (): void => dispatch({ type: SudokuActionType.START })

    // Resume game.
    const resumeGame = (): void => dispatch({ type: SudokuActionType.RESUME })

    switch (state.gameStatus) {
      case GameRunningStatus.PENDING: {
        return (
          <div className="kyokuya-sudoku__overlay">
            <Button
              className="kyokuya-sudoku__start-button"
              variant="contained"
              color="primary"
              startIcon={<GamePendingIcon />}
              onClick={startGame}
            >
              Start
            </Button>
          </div>
        )
      }
      case GameRunningStatus.PAUSED: {
        return (
          <div className="kyokuya-sudoku__overlay">
            <Button
              variant="contained"
              color="primary"
              startIcon={<GamePausedIcon />}
              onClick={resumeGame}
            >
              Resume
            </Button>
          </div>
        )
      }
      case GameRunningStatus.FINISHED: {
        return (
          <div className="kyokuya-sudoku__overlay">
            <p className="kyokuya-sudoku__finished-banner">🎉 You win!</p>
          </div>
        )
      }
      default:
        return null
    }
  }, [state.gameStatus, dispatch])
}

GameOverlay.displayName = 'SudokuGameOverlay'
